'use client';

import { useState, useRef, useEffect } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { RecaptchaVerifier, signInWithPhoneNumber, ConfirmationResult } from 'firebase/auth';
import { auth } from '@/lib/firebase';
import { useAuth } from '@/context/AuthContext';

declare global {
  interface Window {
    recaptchaVerifier: RecaptchaVerifier;
    confirmationResult: ConfirmationResult;
  }
}

export default function AuthPage() {
  const [step, setStep] = useState<'phone' | 'otp'>('phone');
  const [phone, setPhone] = useState('');
  const [countryCode, setCountryCode] = useState('+91');
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const otpRefs = useRef<(HTMLInputElement | null)[]>([]);
  const router = useRouter();
  const { user, profile, loading: authLoading } = useAuth();

  useEffect(() => {
    if (!authLoading && user) {
      if (profile?.profileCompleted) {
        router.push('/swipe');
      } else {
        router.push('/profile/edit');
      }
    }
  }, [user, profile, authLoading, router]);

  const setupRecaptcha = () => {
    if (!window.recaptchaVerifier) {
      window.recaptchaVerifier = new RecaptchaVerifier(auth, 'recaptcha-container', {
        size: 'invisible',
        callback: () => { },
      });
    }
  };

  const handleSendOtp = async () => {
    if (phone.length < 10) { setError('Enter a valid phone number'); return; }
    setError(''); setLoading(true);
    try {
      setupRecaptcha();
      const confirmation = await signInWithPhoneNumber(
        auth, `${countryCode}${phone}`, window.recaptchaVerifier
      );
      window.confirmationResult = confirmation;
      setStep('otp');
    } catch (err: unknown) {
      const e = err as { message?: string };
      setError(e.message || 'Failed to send OTP');
      if (window.recaptchaVerifier) {
        window.recaptchaVerifier.clear();
        window.recaptchaVerifier = undefined as unknown as RecaptchaVerifier;
      }
    } finally { setLoading(false); }
  };

  const handleOtpChange = (index: number, value: string) => {
    if (value.length > 1) return;
    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);
    if (value && index < 5) otpRefs.current[index + 1]?.focus();
  };

  const handleOtpKeyDown = (index: number, e: React.KeyboardEvent) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      otpRefs.current[index - 1]?.focus();
    }
  };

  const handleVerifyOtp = async () => {
    const code = otp.join('');
    if (code.length !== 6) { setError('Enter the complete OTP'); return; }
    setError(''); setLoading(true);
    try {
      await window.confirmationResult.confirm(code);
    } catch {
      setError('Invalid OTP. Please try again.');
    } finally { setLoading(false); }
  };

  if (authLoading) {
    return <div className="loading-page"><div className="spinner" /></div>;
  }

  return (
    <div className="auth-page">
      <div id="recaptcha-container" />
      <div className="auth-logo-area">
        <div className="auth-logo">Campus<span>Link</span></div>
        <p className="auth-tagline">connect · collaborate · create</p>
      </div>

      <div className="auth-form">
        {step === 'phone' ? (
          <>
            <div>
              <label className="auth-label">Phone Number</label>
              <div className="auth-input-row">
                <select
                  value={countryCode}
                  onChange={(e) => setCountryCode(e.target.value)}
                  className="auth-select"
                >
                  <option value="+91">+91</option>
                  <option value="+1">+1</option>
                  <option value="+44">+44</option>
                  <option value="+61">+61</option>
                </select>
                <input
                  type="tel"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value.replace(/\D/g, ''))}
                  placeholder="9876543210"
                  maxLength={10}
                  className="auth-input"
                />
              </div>
            </div>
            {error && <p className="auth-error">{error}</p>}
            <button
              onClick={handleSendOtp}
              disabled={loading || phone.length < 10}
              className="auth-btn"
            >
              {loading ? 'Sending...' : 'Continue →'}
            </button>
            <p className="auth-note">
              Your identity remains anonymous. Phone is only used for verification.
            </p>
          </>
        ) : (
          <>
            <div>
              <label className="auth-label">Verification Code</label>
              <p style={{ fontSize: 12, color: 'var(--subtle)', marginBottom: 12 }}>
                Sent to {countryCode}{phone}
              </p>
              <div className="otp-row">
                {otp.map((digit, i) => (
                  <input
                    key={i}
                    ref={(el) => { otpRefs.current[i] = el; }}
                    type="text"
                    inputMode="numeric"
                    maxLength={1}
                    value={digit}
                    onChange={(e) => handleOtpChange(i, e.target.value)}
                    onKeyDown={(e) => handleOtpKeyDown(i, e)}
                    className="otp-input"
                  />
                ))}
              </div>
            </div>
            {error && <p className="auth-error">{error}</p>}
            <button
              onClick={handleVerifyOtp}
              disabled={loading || otp.join('').length !== 6}
              className="auth-btn"
            >
              {loading ? 'Verifying...' : 'Verify & Enter →'}
            </button>
            <button
              onClick={() => { setStep('phone'); setOtp(['', '', '', '', '', '']); setError(''); }}
              className="auth-link"
            >
              ← Change phone number
            </button>
          </>
        )}
      </div>
    </div>
  );
}
